  function showActionFeedback(message: string, durationMs = 2600) {
    setActionFeedback(message);
    if (actionFeedbackTimerRef.current) {
      window.clearTimeout(actionFeedbackTimerRef.current);
    }
    actionFeedbackTimerRef.current = window.setTimeout(() => {
      setActionFeedback("");
      actionFeedbackTimerRef.current = undefined;
    }, durationMs);
  }

  function showCaptureNotice(notice: CaptureNotice, durationMs = 8500) {
    setCaptureNotice(notice);
    if (captureNoticeTimerRef.current) {
      window.clearTimeout(captureNoticeTimerRef.current);
    }
    captureNoticeTimerRef.current = window.setTimeout(() => {
      setCaptureNotice(null);
      captureNoticeTimerRef.current = undefined;
    }, durationMs);
  }

  function applyGameZoom(zoom = gameZoom) {
    const webview = gameRef.current;
    if (!webview) {
      return;
    }
    try {
      webview.setZoomFactor(clampGameZoom(zoom));
      (webview as Electron.WebviewTag & { setVisualZoomLevelLimits?: (minimumLevel: number, maximumLevel: number) => Promise<void> })
        .setVisualZoomLevelLimits?.(1, 1)
        .catch(() => undefined);
    } catch {
      // The webview can be between navigations; the next ready event reapplies the saved zoom.
    }
  }

  function reloadGamePage(hardRefresh = false) {
    const webview = gameRef.current as (Electron.WebviewTag & { reloadIgnoringCache?: () => void }) | null;
    if (!webview) {
      showActionFeedback("Game page is not ready yet.");
      return;
    }
    try {
      if (hardRefresh && typeof webview.reloadIgnoringCache === "function") {
        webview.reloadIgnoringCache();
      } else {
        webview.reload();
      }
      showActionFeedback(hardRefresh ? "Hard refreshing game page..." : "Refreshing game page...");
    } catch {
      showActionFeedback("Refresh failed. Try switching tabs and back.");
    }
  }

  async function recoverAtlasWebview() {
    if (atlasRecoveryBusy) {
      return;
    }
    setAtlasRecoveryBusy(true);
    showActionFeedback("Repairing the embedded Atlas browser...", 6_000);
    try {
      const result = await window.riftlite.recoverAtlasWebview();
      if (!result.ok) {
        showActionFeedback(result.message, 7_000);
        return;
      }
      atlasReloadStormRef.current = initialAtlasReloadStormState();
      setAtlasRecoverySuggested(false);
      reloadGamePage(true);
      showActionFeedback(result.message, 6_000);
    } catch (error) {
      showActionFeedback(
        error instanceof Error ? `Atlas repair failed: ${error.message}` : "Atlas repair failed. Restart RiftLite and try again.",
        7_000
      );
    } finally {
      setAtlasRecoveryBusy(false);
    }
  }

  async function setGameZoom(nextZoom: number) {
    const zoom = clampGameZoom(nextZoom);
    applyGameZoom(zoom);
    await saveSettings({ gameZoomFactor: zoom });
    showActionFeedback(`Game zoom set to ${Math.round(zoom * 100)}%.`);
  }

  async function handleWebviewIpc(event: { channel?: string; args?: unknown[] }) {
    if (event.channel !== "capture:event") {
      return;
    }
    const payload = event.args?.[0];
    if (!payload || typeof payload !== "object") {
      return;
    }
    const captureEvent = payload as CaptureEvent;
    const nextRecoveryState = updateAtlasReloadStormState(
      atlasReloadStormRef.current,
      captureEvent
    );
    atlasReloadStormRef.current = nextRecoveryState;
    setAtlasRecoverySuggested(nextRecoveryState.suggested);
    await window.riftlite.reportRendererEvent(captureEvent);
  }

  async function primeReplayVideoTarget(platform: GamePlatform = activePlatform): Promise<void> {
    const currentSettings = settingsRef.current;
    const mode: ReplayVideoCaptureMode = "game-frame";
    if (
      !currentSettings?.replayCaptureEnabled ||
      !currentSettings.replayVideoEnabled
    ) {
      return;
    }
    await window.riftlite.prepareReplayVideoCaptureTarget(platform, mode);
  }

  function reportReplayVideoDebug(platform: GamePlatform, reason: string, details: Record<string, unknown> = {}): void {
    const capturedAt = new Date().toISOString();
    void window.riftlite.reportRendererEvent({
      id: `${platform}-replay-video-${crypto.randomUUID?.() ?? `${Date.now()}-${Math.random()}`}`,
      platform,
      kind: "debug",
      capturedAt,
      url: GAME_URLS[platform],
      payload: {
        reason: `replay-video-${reason}`,
        activeView: activeViewRef.current,
        ...details
      }
    });
  }

  function stopReplaySource(source: SystemWindowReplaySource | undefined): void {
    source?.stream.getTracks().forEach((track) => track.stop());
    if (source?.video) {
      source.video.pause();
      source.video.srcObject = null;
    }
  }

  function stopArmedReplaySources(): void {
    for (const armed of Object.values(armedReplayVideoRef.current)) {
      stopReplaySource(armed?.source);
    }
    armedReplayVideoRef.current = {};
  }

  function takeArmedReplaySource(
    platform: GamePlatform,
    mode: ReplayVideoCaptureMode,
    quality: ReplayVideoQuality
  ): SystemWindowReplaySource | null {
    const armed = armedReplayVideoRef.current[platform];
    if (!armed || armed.mode !== mode || armed.quality !== quality) {
      return null;
    }
    if (!armed.source.stream.getVideoTracks().some((track) => track.readyState === "live")) {
      delete armedReplayVideoRef.current[platform];
      return null;
    }
    delete armedReplayVideoRef.current[platform];
    return armed.source;
  }

  async function armReplayVideoSource(platform: GamePlatform = activePlatform, quiet = true): Promise<void> {
    const currentSettings = settingsRef.current;
    const mode: ReplayVideoCaptureMode = "game-frame";
    if (
      !currentSettings?.replayCaptureEnabled ||
      !currentSettings.replayVideoEnabled ||
      replayVideoRef.current
    ) {
      return;
    }
    const quality = currentSettings.replayVideoQuality || "sharp";
    const current = armedReplayVideoRef.current[platform];
    if (
      current?.mode === mode &&
      current.quality === quality &&
      current.source.stream.getVideoTracks().some((track) => track.readyState === "live")
    ) {
      return;
    }
    const now = Date.now();
    if (now - lastReplayArmAttemptRef.current < REPLAY_VIDEO_ARM_THROTTLE_MS) {
      return;
    }
    lastReplayArmAttemptRef.current = now;
    const profile = REPLAY_VIDEO_PROFILES[quality] ?? REPLAY_VIDEO_PROFILES.sharp;
    let source = await prepareDisplayReplaySource(platform, mode, profile, { targetAlreadyPrepared: true });
    if (!source) {
      source = await prepareDisplayReplaySource(platform, mode, profile);
    }
    if (!source) {
      if (!quiet) {
        showActionFeedback("Video replay could not arm yet.");
      }
      reportReplayVideoDebug(platform, "arm-failed", { mode, quality });
      void primeReplayVideoTarget(platform);
      return;
    }
    stopReplaySource(current?.source);
    armedReplayVideoRef.current[platform] = {
      platform,
      mode,
      quality,
      source
    };
    if (!quiet) {
      showActionFeedback("Direct replay capture armed.");
    }
    reportReplayVideoDebug(platform, "armed", { mode, quality, source: source.source });
  }

  async function maybeStartReplayVideo(event: CaptureEvent) {
    const currentSettings = settingsRef.current;
    if (event.kind !== "match-start") {
      return;
    }
    const isResizeResume = event.payload.reason === "replay-video-resize-resume";
    const blockedReason = replayVideoStartBlockedReason(event);
    if (blockedReason) {
      reportReplayVideoDebug(event.platform, "start-skipped", {
        reason: blockedReason,
        capturedAt: event.capturedAt,
        url: event.url,
        payloadReason: event.payload.reason
      });
      return;
    }
    lastReplayStartEventRef.current = event;
    if (
      replayVideoRef.current ||
      !currentSettings?.replayCaptureEnabled ||
      !currentSettings.replayVideoEnabled
    ) {
      return;
    }
    if (typeof MediaRecorder === "undefined") {
      showActionFeedback("Video replay needs MediaRecorder support.");
      reportReplayVideoDebug(event.platform, "media-recorder-missing");
      return;
    }
    const quality = currentSettings.replayVideoQuality || "sharp";
    const profile = REPLAY_VIDEO_PROFILES[quality] ?? REPLAY_VIDEO_PROFILES.sharp;
    const mode: ReplayVideoCaptureMode = "game-frame";
    let displaySource: SystemWindowReplaySource | null = takeArmedReplaySource(event.platform, mode, quality);
    displaySource = displaySource ?? await prepareDisplayReplaySource(event.platform, mode, profile);
    if (!displaySource) {
      showActionFeedback("Video replay was not armed, so it was skipped to keep gameplay smooth.");
      reportReplayVideoDebug(event.platform, "start-source-missing", { mode, quality });
      void primeReplayVideoTarget(event.platform);
      return;
    }
    let canvas: HTMLCanvasElement | undefined;
    let context: CanvasRenderingContext2D | undefined;
    let stream: MediaStream;
    let sourceStream: MediaStream | undefined;
    let sourceVideo: ReplaySourceVideoElement | undefined;
    let source: ReplayVideoFinalizeOptions["source"];
    let width = displaySource?.width ?? profile.width;
    let height = displaySource?.height ?? profile.height;

    const useConstantFpsDirect = displaySource.source === "game-frame-direct" && profile.constantFps;
    if (displaySource.source === "game-frame-direct" && !useConstantFpsDirect) {
      stream = displaySource.stream;
      sourceStream = displaySource.stream;
      source = "game-frame-direct";
    } else {
      canvas = document.createElement("canvas");
      canvas.width = profile.width;
      canvas.height = profile.height;
      context = canvas.getContext("2d", { alpha: false, desynchronized: true } as CanvasRenderingContext2DSettings) ?? undefined;
      if (!context) {
        displaySource.stream.getTracks().forEach((track) => track.stop());
        reportReplayVideoDebug(event.platform, "canvas-context-missing", { mode, quality, source: displaySource.source });
        return;
      }
      context.imageSmoothingEnabled = true;
      context.imageSmoothingQuality = useConstantFpsDirect ? "medium" : "low";
      stream = canvas.captureStream(profile.fps);
      width = profile.width;
      height = profile.height;
      sourceStream = displaySource.stream;
      if (useConstantFpsDirect) {
        sourceVideo = document.createElement("video") as ReplaySourceVideoElement;
        sourceVideo.muted = true;
        sourceVideo.playsInline = true;
        sourceVideo.srcObject = displaySource.stream;
        await sourceVideo.play();
        if (!sourceVideo.videoWidth || !sourceVideo.videoHeight) {
          await new Promise<void>((resolve) => {
            const done = () => resolve();
            sourceVideo?.addEventListener("loadedmetadata", done, { once: true });
            window.setTimeout(done, 500);
          });
        }
        source = "game-frame-direct";
      } else {
        sourceVideo = displaySource.video;
        source = "system-window-crop";
      }
    }
    let micStream: MediaStream | undefined;
    let recorderStream = stream;
    if (currentSettings.replayMicAudioEnabled) {
      try {
        micStream = await createReplayMicrophoneStream(currentSettings.microphoneDeviceId);
        const audioTracks = micStream.getAudioTracks();
        if (audioTracks.length) {
          recorderStream = new MediaStream([...stream.getVideoTracks(), ...audioTracks]);
        } else {
          micStream.getTracks().forEach((track) => track.stop());
          micStream = undefined;
        }
      } catch (error) {
        showActionFeedback("Replay microphone could not start; video replay continues without voice.");
        reportReplayVideoDebug(event.platform, "microphone-start-failed", {
          message: error instanceof Error ? error.message : String(error)
        });
      }
    }
    const recorderFormats = supportedReplayVideoFormats(Boolean(micStream));
    if (!recorderFormats.length) {
      micStream?.getTracks().forEach((track) => track.stop());
      sourceStream?.getTracks().forEach((track) => track.stop());
      if (stream !== sourceStream) {
        stream.getTracks().forEach((track) => track.stop());
      }
      showActionFeedback("Video replay needs MediaRecorder video support.");
      reportReplayVideoDebug(event.platform, "recorder-format-missing", { mode, quality, source });
      return;
    }
    let recorder: MediaRecorder | null = null;
    let recorderFormat: ReplayRecorderFormat | null = null;
    for (const candidate of recorderFormats) {
      try {
        recorder = new MediaRecorder(recorderStream, {
          mimeType: candidate.recorderMimeType,
          bitsPerSecond: profile.bitrateKbps * 1000,
          videoBitsPerSecond: profile.bitrateKbps * 1000,
          ...(micStream ? { audioBitsPerSecond: 96_000 } : {})
        });
        recorderFormat = candidate;
        break;
      } catch {
        recorder = null;
      }
    }
    if (!recorder || !recorderFormat) {
      micStream?.getTracks().forEach((track) => track.stop());
      sourceStream?.getTracks().forEach((track) => track.stop());
      if (stream !== sourceStream) {
        stream.getTracks().forEach((track) => track.stop());
      }
      showActionFeedback("Video replay could not create a recorder.");
      reportReplayVideoDebug(event.platform, "recorder-create-failed", { mode, quality, source });
      return;
    }
    const session = await window.riftlite.startReplayVideoCapture({
      platform: event.platform,
      title: `${event.platform}-${event.capturedAt}`,
      quality,
      mimeType: recorderFormat.fileMimeType
    });
    const runtime: ReplayVideoRuntime = {
      session,
      platform: event.platform,
      startEvent: event,
      mode,
      source,
      profile,
      quality,
      fileMimeType: recorderFormat.fileMimeType,
      codec: recorderFormat.codec,
      canvas,
      context,
      recorder,
      stream: recorderStream,
      width,
      height,
      timer: 0,
      sourceStream,
      micStream,
      hasAudio: Boolean(micStream),
      sourceVideo,
      videoFrameCallbackId: undefined,
      cropCache: undefined,
      startedAt: session.startedAt,
      startedMs: Date.now(),
      pendingWrites: [],
      writeChain: Promise.resolve(),
      frameCount: 0,
      lastDrawAt: 0,
      nextAllowedAt: Date.now() + 1000,
      slowCaptureStreak: 0,
      lastCaptureMs: 0,
      chunkMs: REPLAY_VIDEO_WRITE_CHUNK_MS
    };
    recorder.ondataavailable = (chunkEvent) => {
      if (!chunkEvent.data.size) {
        return;
      }
      const capturedAt = Date.now();
      const chunk = chunkEvent.data;
      const shadowRuntime = replayShadowClipRef.current;
      if (shadowRuntime?.parentSessionId === runtime.session.id) {
        shadowRuntime.chunks.push({ data: chunk, capturedAt });
        pruneReplayShadowClipChunks(shadowRuntime, capturedAt);
      }
      const pending = runtime.writeChain
        .catch(() => undefined)
        .then(async () => {
          const buffer = await chunk.arrayBuffer();
          await window.riftlite.appendReplayVideoChunk(session.id, buffer);
        })
        .catch(() => undefined);
      runtime.writeChain = pending;
      runtime.pendingWrites.push(pending);
      pending.finally(() => {
        runtime.pendingWrites = runtime.pendingWrites.filter((item) => item !== pending);
      });
    };
    replayVideoRef.current = runtime;
    if (runtime.chunkMs > 0) {
      recorder.start(runtime.chunkMs);
    } else {
      recorder.start();
    }
    installReplayVideoResizeGuard(runtime);
    if (runtime.source === "system-window-crop") {
      drawSystemWindowReplayFrame(runtime);
      scheduleSystemWindowReplayFrame(runtime);
    } else if (runtime.canvas && runtime.sourceVideo) {
      drawDirectGameFrameReplayFrame(runtime);
      scheduleDirectGameFrameReplayFrame(runtime);
    }
    const modeLabel = runtime.source === "game-frame-direct"
      ? "direct game frame"
      : "window crop";
    if (!isResizeResume) {
      showActionFeedback(`Video replay started (${profile.label}, ${modeLabel}${runtime.hasAudio ? ", mic on" : ""}).`);
    }
    const recorderTrack = runtime.stream.getVideoTracks()[0] ?? runtime.sourceStream?.getVideoTracks()[0];
    const trackSettings = recorderTrack?.getSettings?.();
    const sourceTrackSettings = runtime.sourceStream?.getVideoTracks()[0]?.getSettings?.();
      reportReplayVideoDebug(event.platform, "started", {
      mode,
      quality,
      source: runtime.source,
      codec: runtime.codec,
      recorderMimeType: recorderFormat.recorderMimeType,
      fileMimeType: recorderFormat.fileMimeType,
      requestedWidth: profile.width,
      requestedHeight: profile.height,
      requestedFps: profile.fps,
      actualWidth: trackSettings?.width,
      actualHeight: trackSettings?.height,
      actualFps: trackSettings?.frameRate,
      sourceWidth: sourceTrackSettings?.width,
      sourceHeight: sourceTrackSettings?.height,
      sourceFps: sourceTrackSettings?.frameRate,
      bitrateKbps: profile.bitrateKbps,
      hasAudio: runtime.hasAudio,
      resampled: Boolean(runtime.canvas && runtime.source === "game-frame-direct"),
      constantFps: Boolean(profile.constantFps),
      chunkMs: runtime.chunkMs
    });
    startReplayShadowClipRuntime(runtime);
  }

  function pruneReplayShadowClipChunks(runtime: ReplayShadowClipRuntime, now = Date.now()): void {
    const keepAfter = now - (normalizeReplayShadowClipSeconds(runtime.clipSeconds) * 1000) - 5000;
    const headerChunk = runtime.chunks[0];
    const recentChunks = runtime.chunks.slice(1).filter((chunk) => chunk.capturedAt >= keepAfter);
    // MediaRecorder containers need their opening metadata. Keep the first chunk as a tiny header anchor.
    runtime.chunks = headerChunk ? [headerChunk, ...recentChunks] : recentChunks;
    if (runtime.chunks.length > 750) {
      const firstChunk = runtime.chunks[0];
      runtime.chunks = firstChunk ? [firstChunk, ...runtime.chunks.slice(-749)] : runtime.chunks.slice(-750);
    }
  }

  function startReplayShadowClipRuntime(parent: ReplayVideoRuntime): void {
    void stopReplayShadowClipRuntime();
    const currentSettings = settingsRef.current;
    if (
      !currentSettings?.replayVideoEnabled ||
      !currentSettings.replayShadowClipEnabled ||
      !currentSettings.replayShadowClipHotkeyEnabled
    ) {
      return;
    }
    const clipSeconds = normalizeReplayShadowClipSeconds(currentSettings.replayShadowClipSeconds);
    const runtime: ReplayShadowClipRuntime = {
      parentSessionId: parent.session.id,
      platform: parent.platform,
      source: parent.source,
      width: parent.width,
      height: parent.height,
      fps: parent.profile.fps,
      bitrateKbps: parent.profile.bitrateKbps,
      quality: parent.quality,
      mimeType: parent.fileMimeType,
      codec: parent.codec,
      hasAudio: parent.hasAudio,
      startedAt: new Date().toISOString(),
      startedMs: Date.now(),
      clipSeconds,
      chunks: []
    };
    replayShadowClipRef.current = runtime;
    reportReplayVideoDebug(parent.platform, "shadow-clip-buffer-started", {
      clipSeconds,
      codec: parent.codec,
      source: "main-recorder-chunks"
    });
  }

  async function stopReplayShadowClipRuntime(): Promise<ReplayShadowClipRuntime | null> {
    const runtime = replayShadowClipRef.current;
    if (!runtime) {
      return null;
    }
    replayShadowClipRef.current = null;
    pruneReplayShadowClipChunks(runtime);
    return runtime;
  }

  function replayShadowClipTitle(runtime: ReplayVideoRuntime, clipSeconds: number): string {
    const payload = runtime.startEvent.payload;
    const myLegend = replayPayloadString(payload, "myChampion");
    const opponentLegend = replayPayloadString(payload, "opponentChampion");
    const matchup = myLegend || opponentLegend ? `${myLegend || "RiftLite"} vs ${opponentLegend || "opponent"}` : "RiftLite replay";
    return `Shadow clip ${clipSeconds}s - ${matchup}`;
  }

  function replayShadowClipRecord(runtime: ReplayVideoRuntime, video: ReplayVideoAsset, clipSeconds: number): ReplayRecord {
    const payload = runtime.startEvent.payload;
    const myName = replayPayloadString(payload, "playerName") || settingsRef.current?.username || "You";
    const opponentName = replayPayloadString(payload, "opponentName") || "Opponent";
    const id = `shadow-${Date.now()}-${crypto.randomUUID()}`;
    return {
      id,
      matchId: id,
      platform: runtime.platform,
      capturedAt: video.endedAt,
      schemaVersion: 4,
      title: replayShadowClipTitle(runtime, clipSeconds),
      players: {
        me: myName,
        opponent: opponentName
      },
      events: [runtime.startEvent],
      video,
      flags: [
        {
          id: crypto.randomUUID(),
          targetType: "video-time",
          targetId: `${video.path || video.url}:0`,
          targetLabel: "Shadow clip start",
          type: "key-turn",
          label: "Shadow clip",
          note: `Created from the previous ${clipSeconds} seconds with the shadow clip hotkey.`,
          capturedAt: video.startedAt,
          createdAt: video.endedAt,
          timeMs: 0
        }
      ]
    };
  }

  async function saveReplayShadowClipFromHotkey(): Promise<void> {
    const parent = replayVideoRef.current;
    const runtime = replayShadowClipRef.current;
    if (!parent || !runtime) {
      showActionFeedback("No active video replay buffer to clip yet.");
      return;
    }
    const clipSeconds = normalizeReplayShadowClipSeconds(settingsRef.current?.replayShadowClipSeconds ?? runtime.clipSeconds);
    try {
      const now = Date.now();
      const clipStartMs = Math.max(runtime.startedMs, now - clipSeconds * 1000);
      pruneReplayShadowClipChunks(runtime, now);
      const headerChunk = runtime.chunks[0];
      const recentChunks = runtime.chunks.filter((chunk) => chunk.capturedAt >= clipStartMs - REPLAY_VIDEO_WRITE_CHUNK_MS);
      const chunks = headerChunk && !recentChunks.includes(headerChunk)
        ? [headerChunk, ...recentChunks]
        : recentChunks;
      if (!chunks.length) {
        showActionFeedback("Shadow clip buffer is still warming up.");
        return;
      }
      const blob = new Blob(chunks.map((chunk) => chunk.data), { type: runtime.mimeType });
      if (!blob.size) {
        showActionFeedback("Shadow clip buffer was empty.");
        return;
      }
      const startedAt = new Date(clipStartMs).toISOString();
      const endedAt = new Date(now).toISOString();
      const title = replayShadowClipTitle(parent, clipSeconds);
      const session = await window.riftlite.startReplayVideoCapture({
        platform: runtime.platform,
        title,
        quality: runtime.quality,
        mimeType: runtime.mimeType
      });
      await window.riftlite.appendReplayVideoChunk(session.id, await blob.arrayBuffer());
      const video = await window.riftlite.finishReplayVideoCapture(session.id, {
        platform: runtime.platform,
        startedAt,
        endedAt,
        durationMs: now - clipStartMs,
        width: runtime.width,
        height: runtime.height,
        fps: runtime.fps,
        captureIntervalMs: Math.round(1000 / Math.max(1, runtime.fps)),
        bitrateKbps: runtime.bitrateKbps,
        actualBitrateKbps: Math.round((blob.size * 8) / Math.max(1, (now - clipStartMs) / 1000) / 1000),
        codec: runtime.codec,
        quality: runtime.quality,
        mimeType: runtime.mimeType,
        source: runtime.source,
        hasAudio: runtime.hasAudio
      });
      await window.riftlite.saveReplay(replayShadowClipRecord(parent, video, clipSeconds));
      setReplays(await window.riftlite.getReplays());
      showActionFeedback(`Shadow clip saved (${formatDuration(video.durationMs)}).`);
      reportReplayVideoDebug(runtime.platform, "shadow-clip-saved", {
        clipSeconds,
        sizeBytes: video.sizeBytes,
        durationMs: video.durationMs
      });
    } catch (error) {
      showActionFeedback(rendererErrorMessage(error, "Shadow clip could not be saved."));
      reportReplayVideoDebug(parent.platform, "shadow-clip-save-failed", {
        message: error instanceof Error ? error.message : String(error)
      });
    } finally {
      // The shadow buffer reuses the main recorder chunks, so the main capture keeps running.
    }
  }

  function addReplayReviewFlagFromHotkey(): void {
    const runtime = replayVideoRef.current;
    if (!runtime) {
      showActionFeedback("No active video replay to flag yet.");
      return;
    }
    const now = new Date();
    const timeMs = Math.max(0, Date.now() - runtime.startedMs);
    const flag: ReplayFlag = {
      id: crypto.randomUUID(),
      targetType: "video-time",
      targetId: `pending-video:${runtime.startedAt}:${Math.round(timeMs)}`,
      targetLabel: `Video ${formatDuration(timeMs)}`,
      type: "key-turn",
      label: "Review later",
      note: "Added with the replay review hotkey during the live match.",
      capturedAt: now.toISOString(),
      createdAt: now.toISOString(),
      timeMs
    };
    pendingReplayHotkeyFlagsRef.current = [
      ...pendingReplayHotkeyFlagsRef.current,
      { platform: runtime.platform, flag }
    ];
    showActionFeedback(`Review flag added at ${formatDuration(timeMs)}.`);
  }

  function takePendingReplayHotkeyFlags(video: ReplayVideoAsset): ReplayFlag[] {
    const startedAt = Date.parse(video.startedAt);
    const endedAt = Date.parse(video.endedAt);
    const targetBase = video.path || video.url || video.filename;
    const matched: ReplayFlag[] = [];
    pendingReplayHotkeyFlagsRef.current = pendingReplayHotkeyFlagsRef.current.filter((item) => {
      if (item.platform !== video.platform) {
        return true;
      }
      const capturedAt = Date.parse(item.flag.capturedAt);
      const belongs = Number.isFinite(capturedAt) &&
        Number.isFinite(startedAt) &&
        Number.isFinite(endedAt) &&
        capturedAt >= startedAt - 5000 &&
        capturedAt <= endedAt + 5000;
      if (!belongs) {
        return true;
      }
      const timeMs = typeof item.flag.timeMs === "number" ? Math.max(0, Math.min(video.durationMs, item.flag.timeMs)) : 0;
      matched.push({
        ...item.flag,
        targetId: `${targetBase}:${Math.round(timeMs)}`,
        targetLabel: `Video ${formatDuration(timeMs)}`,
        capturedAt: replayVideoCapturedAt(video, timeMs),
        timeMs
      });
      return false;
    });
    return matched;
  }

  function mergeReplayFlags(existing: ReplayFlag[] | undefined, additions: ReplayFlag[]): ReplayFlag[] {
    const flags = [...(existing ?? [])];
    const keys = new Set(flags.map((flag) => `${flag.targetType}:${flag.targetId}:${flag.label.toLowerCase()}`));
    for (const flag of additions) {
      const key = `${flag.targetType}:${flag.targetId}:${flag.label.toLowerCase()}`;
      if (keys.has(key)) {
        continue;
      }
      keys.add(key);
      flags.push(flag);
    }
    return flags;
  }

  function replayVideoStartBlockedReason(event: CaptureEvent): string {
    const payloadReason = String(event.payload.reason ?? "");
    const isResizeResume = payloadReason === "replay-video-resize-resume";
    const capturedAt = Date.parse(event.capturedAt);
    if (!Number.isFinite(capturedAt)) {
      return "invalid-captured-at";
    }
    const ageMs = Date.now() - capturedAt;
    if (ageMs > REPLAY_VIDEO_START_MAX_AGE_MS) {
      return "stale-start";
    }
    if (ageMs < -REPLAY_VIDEO_START_FUTURE_TOLERANCE_MS) {
      return "future-start";
    }
    if (!isResizeResume && event.platform === "tcga") {
      try {
        const url = new URL(event.url);
        if (url.hostname.includes("tcg-arena.fr") && !url.pathname.startsWith("/play")) {
          return "tcga-not-play-page";
        }
      } catch {
        return "invalid-url";
      }
    }
    return "";
  }

  async function prepareDisplayReplaySource(
    platform: GamePlatform,
    mode: Extract<ReplayVideoCaptureMode, "game-frame" | "system-window">,
    profile: typeof REPLAY_VIDEO_PROFILES[ReplayVideoQuality],
    options: { targetAlreadyPrepared?: boolean } = {}
  ): Promise<SystemWindowReplaySource | null> {
    if (mode === "system-window") {
      return prepareSystemWindowReplaySource(platform, profile);
    }
    if (!navigator.mediaDevices?.getDisplayMedia) {
      reportReplayVideoDebug(platform, "display-media-missing", { mode });
      return null;
    }
    try {
      if (!options.targetAlreadyPrepared) {
        await window.riftlite.prepareReplayVideoCaptureTarget(platform, mode);
      }
      const videoConstraints = {
        frameRate: { ideal: profile.fps, max: profile.fps },
        width: { ideal: profile.width, max: profile.width },
        height: { ideal: profile.height, max: profile.height },
        resizeMode: "crop-and-scale"
      } as MediaTrackConstraints;
      const sourceStream = await navigator.mediaDevices.getDisplayMedia({
        video: videoConstraints,
        audio: false
      });
      const track = sourceStream.getVideoTracks()[0];
      if (!track) {
        sourceStream.getTracks().forEach((item) => item.stop());
        reportReplayVideoDebug(platform, "display-track-missing", { mode });
        return null;
      }
      try {
        (track as MediaStreamTrack & { contentHint?: string }).contentHint = "detail";
      } catch {
        // Best effort: Chromium uses this hint when available to favour readable card detail.
      }
      await track.applyConstraints({
        width: { ideal: profile.width, max: profile.width },
        height: { ideal: profile.height, max: profile.height },
        frameRate: { max: profile.fps },
        resizeMode: "crop-and-scale"
      } as MediaTrackConstraints).catch(() => undefined);
      const settings = track.getSettings();
      const width = typeof settings.width === "number" && settings.width > 0 ? settings.width : profile.width;
      const height = typeof settings.height === "number" && settings.height > 0 ? settings.height : profile.height;
      return {
        stream: sourceStream,
        width,
        height,
        source: "game-frame-direct"
      };
    } catch (error) {
      reportReplayVideoDebug(platform, "display-source-error", {
        mode,
        targetAlreadyPrepared: Boolean(options.targetAlreadyPrepared),
        message: error instanceof Error ? error.message : String(error),
        name: error instanceof Error ? error.name : ""
      });
      return null;
    }
  }

  async function prepareSystemWindowReplaySource(
    platform: GamePlatform,
    profile: typeof REPLAY_VIDEO_PROFILES[ReplayVideoQuality]
  ): Promise<SystemWindowReplaySource | null> {
    if (!navigator.mediaDevices?.getUserMedia) {
      reportReplayVideoDebug(platform, "window-user-media-missing");
      return null;
    }
    try {
      const captureSource = await window.riftlite.getReplayWindowCaptureSource();
      if (!captureSource) {
        reportReplayVideoDebug(platform, "window-source-missing");
        return null;
      }
      const sourceStream = await navigator.mediaDevices.getUserMedia({
        audio: false,
        video: {
          mandatory: {
            chromeMediaSource: "desktop",
            chromeMediaSourceId: captureSource.id,
            maxWidth: profile.width,
            maxHeight: profile.height,
            maxFrameRate: profile.fps
          }
        }
      } as unknown as MediaStreamConstraints);
      const track = sourceStream.getVideoTracks()[0];
      if (!track) {
        sourceStream.getTracks().forEach((item) => item.stop());
        reportReplayVideoDebug(platform, "window-track-missing", { sourceName: captureSource.name });
        return null;
      }
      try {
        (track as MediaStreamTrack & { contentHint?: string }).contentHint = "detail";
      } catch {
        // Best effort only.
      }
      const video = document.createElement("video") as ReplaySourceVideoElement;
      video.muted = true;
      video.playsInline = true;
      video.srcObject = sourceStream;
      await video.play();
      if (!video.videoWidth || !video.videoHeight) {
        await new Promise<void>((resolve) => {
          const done = () => resolve();
          video.addEventListener("loadedmetadata", done, { once: true });
          window.setTimeout(done, 500);
        });
      }
      reportReplayVideoDebug(platform, "window-source-ready", { sourceName: captureSource.name });
      return {
        stream: sourceStream,
        video,
        width: profile.width,
        height: profile.height,
        source: "system-window-crop"
      };
    } catch (error) {
      reportReplayVideoDebug(platform, "window-source-error", {
        message: error instanceof Error ? error.message : String(error),
        name: error instanceof Error ? error.name : ""
      });
      return null;
    }
  }

  function scheduleSystemWindowReplayFrame(runtime: ReplayVideoRuntime): void {
    const video = runtime.sourceVideo;
    if (!video || runtime.recorder.state === "inactive") {
      return;
    }
    if (video.requestVideoFrameCallback) {
      runtime.videoFrameCallbackId = video.requestVideoFrameCallback(() => {
        drawSystemWindowReplayFrame(runtime);
        scheduleSystemWindowReplayFrame(runtime);
      });
      return;
    }
    if (!runtime.timer) {
      runtime.timer = window.setInterval(() => {
        drawSystemWindowReplayFrame(runtime);
      }, Math.max(SYSTEM_REPLAY_FRAME_MIN_MS, Math.floor(1000 / Math.max(1, runtime.profile.fps))));
    }
  }

  function scheduleDirectGameFrameReplayFrame(runtime: ReplayVideoRuntime): void {
    if (!runtime.sourceVideo || !runtime.canvas || runtime.recorder.state === "inactive" || runtime.timer) {
      return;
    }
    runtime.timer = window.setInterval(() => {
      drawDirectGameFrameReplayFrame(runtime);
    }, Math.max(SYSTEM_REPLAY_FRAME_MIN_MS, Math.floor(1000 / Math.max(1, runtime.profile.fps))));
  }

  function drawDirectGameFrameReplayFrame(runtime: ReplayVideoRuntime): void {
    if (runtime.source !== "game-frame-direct" || runtime.recorder.state === "inactive" || !runtime.context || !runtime.canvas) {
      return;
    }
    const now = Date.now();
    const minFrameGap = Math.max(SYSTEM_REPLAY_FRAME_MIN_MS, Math.floor(1000 / Math.max(1, runtime.profile.fps)));
    if (runtime.lastDrawAt && now - runtime.lastDrawAt < minFrameGap) {
      return;
    }
    const video = runtime.sourceVideo;
    if (!video || video.readyState < HTMLMediaElement.HAVE_CURRENT_DATA || !video.videoWidth || !video.videoHeight) {
      return;
    }
    runtime.context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight, 0, 0, runtime.canvas.width, runtime.canvas.height);
    runtime.frameCount += 1;
    runtime.lastDrawAt = now;
  }

  function systemReplayCrop(runtime: ReplayVideoRuntime, video: HTMLVideoElement): SystemReplayCrop | null {
    const frame = document.querySelector<HTMLElement>(".game-frame");
    const rect = frame?.getBoundingClientRect();
    const viewportWidth = Math.max(1, window.innerWidth);
    const viewportHeight = Math.max(1, window.innerHeight);
    if (!rect || rect.width < 32 || rect.height < 32) {
      return null;
    }
    const sourceWidth = video.videoWidth;
    const sourceHeight = video.videoHeight;
    const outerWidth = Math.max(viewportWidth, window.outerWidth || viewportWidth);
    const outerHeight = Math.max(viewportHeight, window.outerHeight || viewportHeight);
    const cacheKey = [
      sourceWidth,
      sourceHeight,
      viewportWidth,
      viewportHeight,
      outerWidth,
      outerHeight,
      Math.round(rect.left),
      Math.round(rect.top),
      Math.round(rect.width),
      Math.round(rect.height)
    ].join(":");
    const now = Date.now();
    if (runtime.cropCache?.cacheKey === cacheKey && runtime.cropCache.expiresAt > now) {
      return runtime.cropCache;
    }
    const sourceAspect = sourceWidth / Math.max(1, sourceHeight);
    const innerAspect = viewportWidth / Math.max(1, viewportHeight);
    const outerAspect = outerWidth / Math.max(1, outerHeight);
    const capturesNativeFrame = Math.abs(sourceAspect - outerAspect) + 0.01 < Math.abs(sourceAspect - innerAspect);
    const horizontalFrame = capturesNativeFrame ? Math.max(0, (outerWidth - viewportWidth) / 2) : 0;
    const topFrame = capturesNativeFrame ? Math.max(0, outerHeight - viewportHeight - horizontalFrame) : 0;
    const basisWidth = capturesNativeFrame ? outerWidth : viewportWidth;
    const basisHeight = capturesNativeFrame ? outerHeight : viewportHeight;
    const sx = Math.max(0, Math.min(sourceWidth - 1, ((rect.left + horizontalFrame) / basisWidth) * sourceWidth));
    const sy = Math.max(0, Math.min(sourceHeight - 1, ((rect.top + topFrame) / basisHeight) * sourceHeight));
    const sw = Math.max(1, Math.min(sourceWidth - sx, (rect.width / basisWidth) * sourceWidth));
    const sh = Math.max(1, Math.min(sourceHeight - sy, (rect.height / basisHeight) * sourceHeight));
    runtime.cropCache = {
      sx,
      sy,
      sw,
      sh,
      cacheKey,
      expiresAt: now + SYSTEM_REPLAY_CROP_CACHE_MS
    };
    return runtime.cropCache;
  }

  function drawSystemWindowReplayFrame(runtime: ReplayVideoRuntime): void {
    if (runtime.source !== "system-window-crop" || runtime.recorder.state === "inactive" || !runtime.context || !runtime.canvas) {
      return;
    }
    const now = Date.now();
    if (runtime.nextAllowedAt > now) {
      return;
    }
    const minFrameGap = Math.max(SYSTEM_REPLAY_FRAME_MIN_MS, Math.floor(1000 / Math.max(1, runtime.profile.fps)));
    if (runtime.lastDrawAt && now - runtime.lastDrawAt < minFrameGap) {
      return;
    }
    const started = performance.now();
    const video = runtime.sourceVideo;
    try {
      if (!video || video.readyState < HTMLMediaElement.HAVE_CURRENT_DATA || !video.videoWidth || !video.videoHeight) {
        return;
      }
      if (activeViewRef.current !== "play") {
        return;
      }
      const crop = systemReplayCrop(runtime, video);
      if (!crop) {
        return;
      }
      runtime.context.drawImage(video, crop.sx, crop.sy, crop.sw, crop.sh, 0, 0, runtime.canvas.width, runtime.canvas.height);
      runtime.frameCount += 1;
      runtime.lastDrawAt = now;
    } finally {
      runtime.lastCaptureMs = performance.now() - started;
      if (runtime.lastCaptureMs > SYSTEM_REPLAY_SLOW_DRAW_MS) {
        runtime.slowCaptureStreak += 1;
        runtime.nextAllowedAt = Date.now() + Math.min(
          SYSTEM_REPLAY_MAX_BACKOFF_MS,
          SYSTEM_REPLAY_BACKOFF_STEP_MS * runtime.slowCaptureStreak
        );
      } else if (runtime.slowCaptureStreak > 0) {
        runtime.slowCaptureStreak -= 1;
        runtime.nextAllowedAt = 0;
      }
    }
  }

  function installReplayVideoResizeGuard(runtime: ReplayVideoRuntime): void {
    if (runtime.source !== "game-frame-direct") {
      return;
    }
    const baselineWidth = window.innerWidth;
    const baselineHeight = window.innerHeight;
    let lastWindowWidth = window.innerWidth;
    let lastWindowHeight = window.innerHeight;
    let stopped = false;
    let resizeTimer: number | undefined;
    let pendingResize: { reason: string; details: Record<string, unknown> } | null = null;
    const stopForResize = (reason: string, details: Record<string, unknown>) => {
      if (stopped || replayVideoRef.current !== runtime) {
        return;
      }
      stopped = true;
      reportReplayVideoDebug(runtime.platform, "resize-guard-stopped", {
        reason,
        baselineWidth,
        baselineHeight,
        ...details
      });
      void stopReplayVideoForDraft(null, { retainForLater: true, reason: "resize", resumeAfterResize: true });
    };
    const scheduleResizeStop = (reason: string, details: Record<string, unknown>) => {
      pendingResize = { reason, details };
      if (resizeTimer) {
        window.clearTimeout(resizeTimer);
      }
      resizeTimer = window.setTimeout(() => {
        resizeTimer = undefined;
        const pending = pendingResize;
        pendingResize = null;
        if (!pending) {
          return;
        }
        stopForResize(pending.reason, pending.details);
      }, REPLAY_VIDEO_RESIZE_GUARD_MS);
    };
    const onWindowResize = () => {
      const nextWidth = window.innerWidth;
      const nextHeight = window.innerHeight;
      const windowMoved = Math.abs(nextWidth - lastWindowWidth) > REPLAY_VIDEO_RESIZE_DELTA_PX ||
        Math.abs(nextHeight - lastWindowHeight) > REPLAY_VIDEO_RESIZE_DELTA_PX;
      lastWindowWidth = nextWidth;
      lastWindowHeight = nextHeight;
      if (!windowMoved) {
        return;
      }
      scheduleResizeStop("window-resize", {
        innerWidth: window.innerWidth,
        innerHeight: window.innerHeight,
        outerWidth: window.outerWidth,
        outerHeight: window.outerHeight
      });
    };
    window.addEventListener("resize", onWindowResize);
    runtime.resizeGuardCleanup = () => {
      window.removeEventListener("resize", onWindowResize);
      if (resizeTimer) {
        window.clearTimeout(resizeTimer);
      }
    };
  }

  async function attachReplayVideoToDraft(draft: MatchDraft, video: ReplayVideoAsset): Promise<void> {
    if (draft.keepReplay === false) {
      takePendingReplayHotkeyFlags(video);
      await window.riftlite.discardReplayVideo(video).catch(() => undefined);
      showActionFeedback("Video replay discarded for this match.");
      return;
    }
    let saved = await window.riftlite.attachReplayVideo(draft.id, video);
    if (saved) {
      const hotkeyFlags = takePendingReplayHotkeyFlags(video);
      if (hotkeyFlags.length) {
        saved = await window.riftlite.saveReplay({
          ...saved,
          schemaVersion: 4,
          flags: mergeReplayFlags(saved.flags, hotkeyFlags)
        });
      }
      setReplays(await window.riftlite.getReplays());
      showActionFeedback(hotkeyFlags.length
        ? `Video replay attached (${formatBytes(video.sizeBytes)}), with ${hotkeyFlags.length} review flag${hotkeyFlags.length === 1 ? "" : "s"}.`
        : `Video replay attached (${formatBytes(video.sizeBytes)}).`);
    }
  }

  async function mergedReplayVideoForDraft(draft: MatchDraft, segments: ReplayVideoAsset[]): Promise<ReplayVideoAsset> {
    const usableSegments = segments.filter((segment) => segment.platform === draft.platform);
    if (usableSegments.length <= 1) {
      return usableSegments[0] ?? segments[0]!;
    }
    try {
      const merged = await window.riftlite.mergeReplayVideos(usableSegments, {
        platform: draft.platform,
        title: `${draft.myChampion || "RiftLite"} vs ${draft.opponentChampion || "opponent"}`,
        quality: usableSegments[0]?.quality || settingsRef.current?.replayVideoQuality || "sharp"
      });
      await Promise.allSettled(usableSegments.map((segment) => window.riftlite.discardReplayVideo(segment)));
      reportReplayVideoDebug(draft.platform, "segments-merged", {
        segmentCount: usableSegments.length,
        sizeBytes: merged.sizeBytes
      });
      return merged;
    } catch (error) {
      reportReplayVideoDebug(draft.platform, "segment-merge-failed", {
        segmentCount: usableSegments.length,
        message: error instanceof Error ? error.message : String(error)
      });
      showActionFeedback("Replay segments were saved, but could not be merged. Attaching the earliest playable segment.");
      return usableSegments[0] ?? usableSegments.at(-1)!;
    }
  }

  function pendingReplayVideoSegment(video: ReplayVideoAsset, startEvent: CaptureEvent | null, reason?: string): PendingReplayVideoSegment {
    return {
      video,
      startEvent,
      retainedAt: new Date().toISOString(),
      reason
    };
  }

  function replayVideoDraftTimeLooksClose(draft: MatchDraft, video: ReplayVideoAsset): boolean {
    const draftAt = Date.parse(draft.capturedAt);
    const startedAt = Date.parse(video.startedAt);
    const endedAt = Date.parse(video.endedAt);
    if (!Number.isFinite(draftAt)) {
      return true;
    }
    if (Number.isFinite(startedAt) && startedAt > draftAt + 60_000) {
      return false;
    }
    if (Number.isFinite(endedAt) && draftAt - endedAt > 20 * 60_000) {
      return false;
    }
    if (Number.isFinite(startedAt) && draftAt - startedAt > 3 * 60 * 60_000) {
      return false;
    }
    return true;
  }

  function replayVideoSegmentMatchesDraft(draft: MatchDraft, segment: PendingReplayVideoSegment): boolean {
    if (segment.video.platform !== draft.platform || !replayVideoDraftTimeLooksClose(draft, segment.video)) {
      return false;
    }
    const startEvent = segment.startEvent;
    if (!startEvent) {
      return true;
    }
    if (startEvent.platform !== draft.platform) {
      return false;
    }
    if (draft.platform === "atlas") {
      const rawEvidence = draft.rawEvidence ?? [];
      const hasSameEvidence = rawEvidence.some((event) => atlasReplayEventsLookLikeSameMatch(startEvent, event));
      if (hasSameEvidence) {
        return true;
      }
      const draftOpponent = normalizeReplayIdentity(draft.opponentName);
      const startOpponent = normalizeReplayIdentity(replayPayloadString(startEvent.payload, "opponentName"));
      if (draftOpponent && startOpponent && draftOpponent !== startOpponent) {
        return false;
      }
      const draftMyLegend = normalizeReplayIdentity(normalizeLegendName(draft.myChampion));
      const startMyLegend = normalizeReplayIdentity(normalizeLegendName(replayPayloadString(startEvent.payload, "myChampion")));
      if (draftMyLegend && startMyLegend && draftMyLegend !== startMyLegend) {
        return false;
      }
      const draftOppLegend = normalizeReplayIdentity(normalizeLegendName(draft.opponentChampion));
      const startOppLegend = normalizeReplayIdentity(normalizeLegendName(replayPayloadString(startEvent.payload, "opponentChampion")));
      if (draftOppLegend && startOppLegend && draftOppLegend !== startOppLegend) {
        return false;
      }
      return Boolean(
        (draftOpponent && startOpponent && draftOpponent === startOpponent) ||
        (draftMyLegend && startMyLegend && draftMyLegend === startMyLegend) ||
        (draftOppLegend && startOppLegend && draftOppLegend === startOppLegend)
      );
    }
    return true;
  }

  async function takeReplayVideoSegmentsForDraft(draft: MatchDraft): Promise<ReplayVideoAsset[]> {
    const seenPaths = new Set<string>();
    const allSegments = [
      ...pendingReplayVideoSegmentsRef.current,
      ...(pendingReplayVideoRef.current ? [pendingReplayVideoRef.current] : [])
    ].filter((segment) => {
      const key = segment.video.path || segment.video.url;
      if (!key || seenPaths.has(key)) {
        return false;
      }
      seenPaths.add(key);
      return true;
    });
    const matched = allSegments.filter((segment) => replayVideoSegmentMatchesDraft(draft, segment));
    const discardSamePlatform = allSegments.filter((segment) => segment.video.platform === draft.platform && !matched.includes(segment));
    const matchedKeys = new Set(matched.map((segment) => segment.video.path || segment.video.url));
    const discardedKeys = new Set(discardSamePlatform.map((segment) => segment.video.path || segment.video.url));
    pendingReplayVideoSegmentsRef.current = pendingReplayVideoSegmentsRef.current.filter((segment) =>
      segment.video.platform !== draft.platform || matched.includes(segment)
    );
    pendingReplayVideoSegmentsRef.current = pendingReplayVideoSegmentsRef.current.filter((segment) => !matched.includes(segment));
    if (
      pendingReplayVideoRef.current?.video.platform === draft.platform
    ) {
      const pendingKey = pendingReplayVideoRef.current.video.path || pendingReplayVideoRef.current.video.url;
      if (matchedKeys.has(pendingKey) || discardedKeys.has(pendingKey)) {
        pendingReplayVideoRef.current = null;
      }
    }
    if (discardSamePlatform.length) {
      reportReplayVideoDebug(draft.platform, "discarding-stale-pending-segments", {
        draftId: draft.id,
        discarded: discardSamePlatform.map((segment) => ({
          startedAt: segment.video.startedAt,
          endedAt: segment.video.endedAt,
          reason: segment.reason,
          startOpponent: segment.startEvent ? replayPayloadString(segment.startEvent.payload, "opponentName") : ""
        }))
      });
      await Promise.allSettled(discardSamePlatform.map((segment) => window.riftlite.discardReplayVideo(segment.video)));
    }
    if (matched.length) {
      reportReplayVideoDebug(draft.platform, "matched-pending-segments", {
        draftId: draft.id,
        segmentCount: matched.length,
        draftOpponent: draft.opponentName,
        starts: matched.map((segment) => segment.video.startedAt)
      });
    }
    return matched.map((segment) => segment.video);
  }

  function scheduleReplayVideoResizeResume(platform: GamePlatform): void {
    if (replayVideoResizeResumeTimerRef.current) {
      window.clearTimeout(replayVideoResizeResumeTimerRef.current);
    }
    reportReplayVideoDebug(platform, "resize-resume-queued");
    replayVideoResizeResumeTimerRef.current = window.setTimeout(() => {
      replayVideoResizeResumeTimerRef.current = undefined;
      const currentSettings = settingsRef.current;
      if (
        replayVideoRef.current ||
        activeViewRef.current !== "play" ||
        !currentSettings?.replayCaptureEnabled ||
        !currentSettings.replayVideoEnabled
      ) {
        return;
      }
      const baseEvent = lastReplayStartEventRef.current;
      const restartEvent: CaptureEvent = {
        id: `${platform}-replay-video-resume-${Date.now()}`,
        platform,
        kind: "match-start",
        capturedAt: new Date().toISOString(),
        url: GAME_URLS[platform],
        payload: {
          ...(baseEvent?.platform === platform ? baseEvent.payload : {}),
          reason: "replay-video-resize-resume"
        }
      };
      reportReplayVideoDebug(platform, "resize-resuming", {
        retainedSegments: pendingReplayVideoSegmentsRef.current.filter((segment) => segment.video.platform === platform).length
      });
      void maybeStartReplayVideo(restartEvent);
    }, REPLAY_VIDEO_RESIZE_RESUME_MS);
  }

  function replayStartEventAfterRuntime(runtime: ReplayVideoRuntime, draft: MatchDraft | null): CaptureEvent | null {
    const pendingStart = lastReplayStartEventRef.current;
    if (!pendingStart || pendingStart.kind !== "match-start" || pendingStart.platform !== runtime.platform) {
      return null;
    }
    if (activeViewRef.current !== "play") {
      return null;
    }
    const currentSettings = settingsRef.current;
    if (!currentSettings?.replayCaptureEnabled || !currentSettings.replayVideoEnabled) {
      return null;
    }
    const pendingAt = Date.parse(pendingStart.capturedAt);
    const startedAt = Date.parse(runtime.startedAt);
    if (!Number.isFinite(pendingAt) || !Number.isFinite(startedAt)) {
      return null;
    }
    const blockedReason = replayVideoStartBlockedReason(pendingStart);
    if (blockedReason) {
      reportReplayVideoDebug(runtime.platform, "rollover-start-skipped", {
        reason: blockedReason,
        pendingCapturedAt: pendingStart.capturedAt,
        runtimeStartedAt: runtime.startedAt
      });
      return null;
    }
    if (
      runtime.platform === "atlas" &&
      draft?.platform === "atlas" &&
      atlasReplayEventsLookLikeSameMatch(runtime.startEvent, pendingStart) &&
      (draft.format === "Bo3" || atlasDraftHasChildGameEvidence(draft) || atlasDraftHasTerminalEvidence(draft))
    ) {
      reportReplayVideoDebug(runtime.platform, "rollover-start-skipped", {
        reason: "atlas-same-bo3-continuation",
        draftId: draft.id,
        draftFormat: draft.format,
        pendingCapturedAt: pendingStart.capturedAt,
        runtimeStartedAt: runtime.startedAt
      });
      return null;
    }
    return pendingAt > startedAt + 1000 ? pendingStart : null;
  }

  async function stopReplayVideoForDraft(
    draft: MatchDraft | null,
    options: { retainForLater?: boolean; reason?: string; resumeAfterResize?: boolean } = {}
  ): Promise<void> {
    if (draft && replayVideoResizeResumeTimerRef.current) {
      window.clearTimeout(replayVideoResizeResumeTimerRef.current);
      replayVideoResizeResumeTimerRef.current = undefined;
    }
    const runtime = replayVideoRef.current;
    if (!runtime) {
      const pendingSegments = draft ? await takeReplayVideoSegmentsForDraft(draft) : [];
      if (draft && pendingSegments.length) {
        const video = await mergedReplayVideoForDraft(draft, pendingSegments);
        await attachReplayVideoToDraft(draft, video);
      }
      return;
    }
    const rolloverStartEvent = draft ? replayStartEventAfterRuntime(runtime, draft) : null;
    replayVideoRef.current = null;
    await stopReplayShadowClipRuntime();
    window.clearInterval(runtime.timer);
    runtime.resizeGuardCleanup?.();
    if (runtime.videoFrameCallbackId !== undefined && runtime.sourceVideo?.cancelVideoFrameCallback) {
      runtime.sourceVideo.cancelVideoFrameCallback(runtime.videoFrameCallbackId);
    }
    try {
      if (runtime.source === "system-window-crop") {
        drawSystemWindowReplayFrame(runtime);
      } else if (runtime.canvas && runtime.sourceVideo) {
        drawDirectGameFrameReplayFrame(runtime);
      }
      const stopped = new Promise<void>((resolve) => {
        runtime.recorder.addEventListener("stop", () => resolve(), { once: true });
      });
      if (runtime.recorder.state !== "inactive") {
        if (runtime.chunkMs > 0) {
          runtime.recorder.requestData();
        }
        runtime.recorder.stop();
      }
      await stopped;
      await runtime.writeChain.catch(() => undefined);
      await Promise.allSettled(runtime.pendingWrites);
      runtime.sourceStream?.getTracks().forEach((track) => track.stop());
      runtime.micStream?.getTracks().forEach((track) => track.stop());
      if (runtime.sourceVideo) {
        runtime.sourceVideo.pause();
        runtime.sourceVideo.srcObject = null;
      }
      if (runtime.stream !== runtime.sourceStream) {
        runtime.stream.getTracks().forEach((track) => track.stop());
      }
      const endedAt = new Date().toISOString();
      const video = await window.riftlite.finishReplayVideoCapture(runtime.session.id, {
        platform: runtime.platform,
        startedAt: runtime.startedAt,
        endedAt,
        durationMs: Date.now() - runtime.startedMs,
        width: runtime.width,
        height: runtime.height,
        fps: runtime.profile.fps,
        captureIntervalMs: Math.round(1000 / Math.max(1, runtime.profile.fps)),
        bitrateKbps: runtime.profile.bitrateKbps,
        actualBitrateKbps: Math.round((runtime.recorder.videoBitsPerSecond || 0) / 1000) || undefined,
        codec: runtime.codec,
        quality: runtime.quality,
        mimeType: runtime.fileMimeType,
        source: runtime.source,
        hasAudio: runtime.hasAudio
      });
      if (draft) {
        const retainedSegments = await takeReplayVideoSegmentsForDraft(draft);
        const currentSegment = pendingReplayVideoSegment(video, runtime.startEvent, "current-runtime");
        const finalVideo = await mergedReplayVideoForDraft(draft, [...retainedSegments, currentSegment.video]);
        await attachReplayVideoToDraft(draft, finalVideo);
      } else if (options.retainForLater) {
        const retainedSegment = pendingReplayVideoSegment(video, runtime.startEvent, options.reason);
        pendingReplayVideoSegmentsRef.current = [
          ...pendingReplayVideoSegmentsRef.current.filter((segment) => segment.video.platform !== video.platform || segment.video.path !== video.path),
          retainedSegment
        ];
        pendingReplayVideoRef.current = retainedSegment;
        if (!options.resumeAfterResize) {
          showActionFeedback("Partial video replay saved and will attach when the match review appears.");
        }
        if (options.resumeAfterResize) {
          scheduleReplayVideoResizeResume(video.platform);
        }
      }
    } catch (error) {
      reportReplayVideoDebug(runtime.platform, "stop-attach-failed", {
        draftId: draft?.id,
        reason: options.reason,
        retainForLater: Boolean(options.retainForLater),
        message: error instanceof Error ? error.message : String(error)
      });
      showActionFeedback("Video replay stopped, but the video could not be attached.");
    }
    if (rolloverStartEvent && !replayVideoRef.current) {
      reportReplayVideoDebug(rolloverStartEvent.platform, "rollover-resuming", {
        previousMatchId: draft?.id
      });
      void maybeStartReplayVideo({
        ...rolloverStartEvent,
        payload: {
          ...rolloverStartEvent.payload,
          reason: "replay-video-rollover-resume"
        }
      });
    }
  }

